export const FALLBACK_COLOR = "#6B7280";

// Resolve a constructor colour for a given season.
export function teamColor(ref: string | null | undefined, year?: number): string {
  if (!ref) return FALLBACK_COLOR;
  const eras = TEAM_COLOR_ERAS[ref];
  if (!eras || eras.length === 0) return FALLBACK_COLOR;
  if (year != null) {
    const hit = eras.find((e) => year >= e.from && year <= e.to);
    if (hit) return hit.hex;
  }
  // No year or no matching era: use the most recent era.
  return eras[eras.length - 1].hex;
}
